/** Случайный приз для базового сундука */ function rollBasicPrize() {
    const r = Math.random();
    if (r < 0.28) return {
        kind: "coins",
        amount: Math.floor(Math.random() * 8) + 1,
        label: "Голоса"
    };
    if (r < 0.5) return {
        kind: "bonus",
        amount: 2,
        label: "Бонусы +2"
    };
    if (r < 0.72) return {
        kind: "voices_small",
        amount: 3 + Math.floor(Math.random() * 5),
        label: "Голоса"
    };
    if (r < 0.9) return {
        kind: "boost",
        amount: 1,
        label: "Быстрый поиск +1"
    };
    return {
        kind: "double_bonus",
        amount: 2,
        label: "Бонусы +2"
    };
}
/** Случайный приз для премиум сундука */ function rollPremiumPrize() {
    const r = Math.random();
    if (r < 0.22) return {
        kind: "coins",
        amount: 10 + Math.floor(Math.random() * 21),
        label: "Голоса"
    };
    if (r < 0.4) return {
        kind: "bonus",
        amount: 2,
        label: "Бонусы +2"
    };
    if (r < 0.58) return {
        kind: "voices_medium",
        amount: 15 + Math.floor(Math.random() * 16),
        label: "Голоса"
    };
    if (r < 0.76) return {
        kind: "boost",
        amount: Math.random() > 0.5 ? 2 : 1,
        label: "Быстрый поиск"
    };
    if (r < 0.9) return {
        kind: "double_bonus",
        amount: 2,
        label: "Бонусы +2"
    };
    return {
        kind: "coins",
        amount: 20 + Math.floor(Math.random() * 25),
        label: "Голоса"
    };
}
/** Выдать N случайных призов для сундука */ function rollChestPrizes(type, count) {
    const roll = type === "premium" ? rollPremiumPrize : rollBasicPrize;
    return Array.from({
        length: count
    }, ()=>roll());
}
/** Применить приз к игроку, вернуть обновлённого игрока */ function applyPrize(prize, player) {
    let balance = player.balance;
    let fastMatchBoosts = player.fastMatchBoosts ?? 0;
    switch(prize.kind){
        case "coins":
        case "voices_small":
        case "voices_medium":
            balance += prize.amount ?? 0;
            break;
        case "bonus":
        case "double_bonus":
            fastMatchBoosts += prize.amount ?? 2;
            break;
        case "boost":
            fastMatchBoosts += prize.amount ?? 1;
            break;
    }
    return {
        balance,
        fastMatchBoosts
    };
}
/** Нормализует массив приглашённых до 4 слотов (null = пусто) */ function normalizeInvitedSlots(invitedFriends) {
    const base = Array.from({
        length: INVITED_SLOTS
    }, (_, i)=>invitedFriends?.[i] ?? null);
    return base;
}
